  .alsel-alternative-products__heading { font-size: clamp(1.4rem, 4vw, 2.2rem); font-weight: 700; margin: 0 0 0.75rem; color: {{ section.settings.text_color }}; }
  .alsel-alternative-products__sub { font-size: 0.95rem; line-height: 1.7; color: {{ section.settings.text_color }}; opacity: 0.85; margin: 0 0 2rem; }
  .alsel-alternative-products__empty { text-align: center; color: #888; padding: 2rem 0; }
  .alsel-alternative-products__grid { display: grid; gap: 1rem; grid-template-columns: repeat({{ section.settings.columns_mobile }}, 1fr); }
