          <div class="alsel-before-after__placeholder" aria-hidden="true">After 画像未設定</div>
        {%- endif -%}
        {%- if section.settings.after_caption != blank -%}
          <figcaption class="alsel-before-after__caption">{{ section.settings.after_caption }}</figcaption>
        {%- endif -%}
      </figure>
    </div>

    {%- if section.settings.note != blank -%}
