<section class="alsel-best-seller-ranking" aria-label="{{ section.settings.heading | escape }}">
  <div class="alsel-best-seller-ranking__inner">
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-best-seller-ranking__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="alsel-best-seller-ranking__sub">{{ section.settings.subheading }}</p>
    {%- endif -%}

    {%- assign target_collection = collections[section.settings.collection] -%}
    {%- if target_collection != blank and target_collection.products.size > 0 -%}
      <ol class="alsel-best-seller-ranking__list">
        {%- for product in target_collection.products limit: section.settings.product_count -%}
          {%- assign rank = forloop.index -%}
          <li class="alsel-best-seller-ranking__item">
            <a class="alsel-best-seller-ranking__link" href="{{ product.url }}" aria-label="{{ product.title | escape }}の詳細を見る">
              <span class="alsel-best-seller-ranking__rank alsel-best-seller-ranking__rank--{{ rank }}">{{ rank }}</span>
              <div class="alsel-best-seller-ranking__image-wrap">
                {%- if product.featured_image != blank -%}
                  {%- assign alt_1 = product.title | escape -%}
{{ product.featured_image
                    | image_url: width: 600
                    | image_tag: loading: 'lazy', class: 'alsel-best-seller-ranking__image', alt: alt_1, widths: '200, 400, 600', sizes: '(min-width: 750px) 300px, 45vw' }}
