                  <span class="alsel-best-seller-ranking__cta">{{ section.settings.button_text }}</span>
                {%- endif -%}
              </div>
            </a>
          </li>
        {%- endfor -%}
      </ol>
    {%- else -%}
      <p class="alsel-best-seller-ranking__empty">表示するコレクションを選択してください。</p>
    {%- endif -%}
  </div>
</section>

