{% comment %}
============================================================
セクション名: 営業日カレンダー風
用途: 店休日や発送休止日をカレンダー形式で表示し、お客様に営業スケジュールを分かりやすく伝える
推奨設置場所: トップページ下部・お買い物ガイドページ・フッター直前など
カスタマイズポイント:
  - 表示する年・月(当月と翌月の 2 ヶ月表示)
  - 店休日・発送休止日・特別営業日のカラー設定
  - 凡例の表示文言
  - 補足メッセージ
  - ブロックで各日付の種別(店休日 / 発送休止日 / 特別営業日)を登録
  - 曜日単位の一括休業設定(毎週日曜は休業など)
注意点:
  - 日付ブロックは「年・月・日」を数値で指定する仕組み
  - ブロックを追加していない月は通常営業日として表示される
  - 曜日一括設定と個別日付指定は併用可能(個別指定が優先される)
  - スマートフォンでは 2 ヶ月を縦に並べて表示する
動作確認バージョン: Online Store 2.0
ライセンス: ALSEL Original
============================================================
{% endcomment %}

{%- assign heading_text = section.settings.heading | escape -%}
{%- assign base_year = section.settings.base_year | times: 1 -%}
{%- assign base_month = section.settings.base_month | times: 1 -%}

<section class="alsel-business-calendar" aria-label="{{ heading_text }}">
  <div class="alsel-business-calendar__inner">
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-business-calendar__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="alsel-business-calendar__sub">{{ section.settings.subheading }}</p>
    {%- endif -%}

    <ul class="alsel-business-calendar__legend" aria-label="凡例">
      <li class="alsel-business-calendar__legend-item">
        <span class="alsel-business-calendar__chip alsel-business-calendar__chip--closed"></span>
        {{ section.settings.label_closed }}
      </li>
      <li class="alsel-business-calendar__legend-item">
        <span class="alsel-business-calendar__chip alsel-business-calendar__chip--noship"></span>
        {{ section.settings.label_noship }}
      </li>
      <li class="alsel-business-calendar__legend-item">
        <span class="alsel-business-calendar__chip alsel-business-calendar__chip--special"></span>
        {{ section.settings.label_special }}
      </li>
    </ul>

    <div class="alsel-business-calendar__months">
      {%- for offset in (0..1) -%}
        {%- assign month_total = base_month | plus: offset -%}
        {%- assign year_add = month_total | minus: 1 | divided_by: 12 -%}
        {%- assign cur_year = base_year | plus: year_add -%}
        {%- assign cur_month = month_total | minus: 1 | modulo: 12 | plus: 1 -%}

        {%- assign days_in_month = 31 -%}
        {%- if cur_month == 4 or cur_month == 6 or cur_month == 9 or cur_month == 11 -%}
          {%- assign days_in_month = 30 -%}
        {%- elsif cur_month == 2 -%}
          {%- assign days_in_month = 28 -%}
          {%- assign y4 = cur_year | modulo: 4 -%}
          {%- assign y100 = cur_year | modulo: 100 -%}
          {%- assign y400 = cur_year | modulo: 400 -%}
          {%- if y4 == 0 and y100 != 0 -%}{%- assign days_in_month = 29 -%}{%- endif -%}
          {%- if y400 == 0 -%}{%- assign days_in_month = 29 -%}{%- endif -%}
        {%- endif -%}

        {%- assign m_calc = cur_month -%}
        {%- assign y_calc = cur_year -%}
        {%- if m_calc < 3 -%}
          {%- assign m_calc = m_calc | plus: 12 -%}
          {%- assign y_calc = y_calc | minus: 1 -%}
        {%- endif -%}
        {%- assign k_yy = y_calc | modulo: 100 -%}
        {%- assign j_century = y_calc | divided_by: 100 -%}
        {%- assign t1 = m_calc | plus: 1 | times: 13 | divided_by: 5 -%}
        {%- assign t2 = k_yy | divided_by: 4 -%}
        {%- assign t3 = j_century | divided_by: 4 -%}
        {%- assign t4 = j_century | times: 5 -%}
        {%- assign h_sum = 1 | plus: t1 | plus: k_yy | plus: t2 | plus: t3 | plus: t4 -%}
        {%- assign h = h_sum | modulo: 7 -%}
        {%- assign first_dow = h | plus: 6 | modulo: 7 -%}

        <div class="alsel-business-calendar__month">
          <h3 class="alsel-business-calendar__month-title">{{ cur_year }}年 {{ cur_month }}月</h3>
          <div class="alsel-business-calendar__grid" role="grid">
            <div class="alsel-business-calendar__cell alsel-business-calendar__cell--head alsel-business-calendar__cell--sun">日</div>
            <div class="alsel-business-calendar__cell alsel-business-calendar__cell--head">月</div>
            <div class="alsel-business-calendar__cell alsel-business-calendar__cell--head">火</div>
            <div class="alsel-business-calendar__cell alsel-business-calendar__cell--head">水</div>
            <div class="alsel-business-calendar__cell alsel-business-calendar__cell--head">木</div>
            <div class="alsel-business-calendar__cell alsel-business-calendar__cell--head">金</div>
            <div class="alsel-business-calendar__cell alsel-business-calendar__cell--head alsel-business-calendar__cell--sat">土</div>

            {%- for i in (1..first_dow) -%}
              <div class="alsel-business-calendar__cell alsel-business-calendar__cell--empty"></div>
            {%- endfor -%}

            {%- for d in (1..days_in_month) -%}
              {%- assign dow_sum = first_dow | plus: d | minus: 1 -%}
              {%- assign dow = dow_sum | modulo: 7 -%}
              {%- assign cell_class = '' -%}
              {%- if dow == 0 -%}{%- assign cell_class = ' alsel-business-calendar__cell--sun' -%}{%- endif -%}
              {%- if dow == 6 -%}{%- assign cell_class = ' alsel-business-calendar__cell--sat' -%}{%- endif -%}

              {%- assign status = '' -%}
              {%- assign status_label = '' -%}

              {%- assign weekly_closed = false -%}
              {%- if dow == 0 and section.settings.holiday_sun -%}{%- assign weekly_closed = true -%}{%- endif -%}
              {%- if dow == 1 and section.settings.holiday_mon -%}{%- assign weekly_closed = true -%}{%- endif -%}
              {%- if dow == 2 and section.settings.holiday_tue -%}{%- assign weekly_closed = true -%}{%- endif -%}
              {%- if dow == 3 and section.settings.holiday_wed -%}{%- assign weekly_closed = true -%}{%- endif -%}
              {%- if dow == 4 and section.settings.holiday_thu -%}{%- assign weekly_closed = true -%}{%- endif -%}
              {%- if dow == 5 and section.settings.holiday_fri -%}{%- assign weekly_closed = true -%}{%- endif -%}
              {%- if dow == 6 and section.settings.holiday_sat -%}{%- assign weekly_closed = true -%}{%- endif -%}
              {%- if weekly_closed -%}
                {%- assign status = 'closed' -%}
                {%- assign status_label = section.settings.label_closed -%}
              {%- endif -%}

              {%- for block in section.blocks -%}
                {%- assign b_year = block.settings.year | times: 1 -%}
                {%- assign b_month = block.settings.month | times: 1 -%}
                {%- assign b_day = block.settings.day | times: 1 -%}
                {%- if b_year == cur_year and b_month == cur_month and b_day == d -%}
                  {%- assign status = block.settings.status -%}
                  {%- if status == 'closed' -%}{%- assign status_label = section.settings.label_closed -%}{%- endif -%}
                  {%- if status == 'noship' -%}{%- assign status_label = section.settings.label_noship -%}{%- endif -%}
                  {%- if status == 'special' -%}{%- assign status_label = section.settings.label_special -%}{%- endif -%}
                {%- endif -%}
              {%- endfor -%}

              <div class="alsel-business-calendar__cell alsel-business-calendar__cell--day{{ cell_class }}{%- if status != '' %} alsel-business-calendar__cell--{{ status }}{%- endif -%}"
                {%- if status_label != '' %} aria-label="{{ cur_month }}月{{ d }}日 {{ status_label | escape }}"{%- endif -%}>
                <span class="alsel-business-calendar__num">{{ d }}</span>
              </div>
            {%- endfor -%}
          </div>
        </div>
      {%- endfor -%}
    </div>

    {%- if section.settings.note != blank -%}
      <p class="alsel-business-calendar__note">{{ section.settings.note }}</p>
    {%- endif -%}
  </div>
</section>

