  .alsel-comic-story-section__panel-number { position: absolute; top: -18px; left: -10px; width: 44px; height: 44px; background: var(--accent); color: #fff; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-weight: 700; font-size: 1.2rem; border: 3px solid var(--frame); }
