{% comment %}
============================================================
セクション名: 競合比較表
用途: 自社商品と一般品の違いを表形式で見せることで、購入前の不安を払拭し優位性を伝える
推奨設置場所: 商品ページの説明エリア・LP の中盤(特徴紹介の後・お客様の声の前)
カスタマイズポイント:
  - セクション見出し・サブコピー
  - 比較する列のラベル(自社・他社 A・他社 B など)
  - 比較項目(ブロックで自由に追加・削除)
  - 各項目ごとの評価(◎・○・△・×・自由入力)
  - 強調色・背景色・自社列のハイライト色
注意点:
  - 比較項目は 4〜8 個が読みやすい目安
  - 比較列は 2〜4 列推奨。CSS の grid 列数は自動調整される
  - 景品表示法・薬機法に抵触する誇大表現は避けること
動作確認バージョン: Online Store 2.0
ライセンス: ALSEL Original
============================================================
{% endcomment %}

{%- assign col_count = 0 -%}
{%- if section.settings.col1_label != blank -%}{%- assign col_count = col_count | plus: 1 -%}{%- endif -%}
{%- if section.settings.col2_label != blank -%}{%- assign col_count = col_count | plus: 1 -%}{%- endif -%}
{%- if section.settings.col3_label != blank -%}{%- assign col_count = col_count | plus: 1 -%}{%- endif -%}
{%- assign total_cols = col_count | plus: 1 -%}

<section class="alsel-competitor-comparison" aria-label="{{ section.settings.heading | escape }}">
  <div class="alsel-competitor-comparison__inner">
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-competitor-comparison__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="alsel-competitor-comparison__sub">{{ section.settings.subheading }}</p>
    {%- endif -%}

    {%- if section.blocks.size == 0 -%}
      <p class="alsel-competitor-comparison__empty">
        比較項目はまだ登録されていません。テーマエディタからブロックを追加してください。
      </p>
    {%- else -%}
      <div class="alsel-competitor-comparison__scroll">
        <table class="alsel-competitor-comparison__table" style="--col-total: {{ total_cols }};">
          <thead>
            <tr>
              <th class="alsel-competitor-comparison__th alsel-competitor-comparison__th--item" scope="col">
                {{ section.settings.item_header }}
              </th>
              <th class="alsel-competitor-comparison__th alsel-competitor-comparison__th--own" scope="col">
                {%- if section.settings.own_badge != blank -%}
                  <span class="alsel-competitor-comparison__badge">{{ section.settings.own_badge }}</span>
                {%- endif -%}
                <span class="alsel-competitor-comparison__col-label">{{ section.settings.col1_label }}</span>
              </th>
              {%- if section.settings.col2_label != blank -%}
                <th class="alsel-competitor-comparison__th" scope="col">{{ section.settings.col2_label }}</th>
              {%- endif -%}
              {%- if section.settings.col3_label != blank -%}
                <th class="alsel-competitor-comparison__th" scope="col">{{ section.settings.col3_label }}</th>
              {%- endif -%}
            </tr>
          </thead>
          <tbody>
            {%- for block in section.blocks -%}
              <tr {{ block.shopify_attributes }}>
                <th class="alsel-competitor-comparison__row-head" scope="row">
                  {{ block.settings.item_name }}
                </th>
                <td class="alsel-competitor-comparison__cell alsel-competitor-comparison__cell--own">
                  <span class="alsel-competitor-comparison__mark alsel-competitor-comparison__mark--{{ block.settings.own_mark }}">
                    {%- case block.settings.own_mark -%}
                      {%- when 'best' -%}◎
                      {%- when 'good' -%}○
                      {%- when 'fair' -%}△
                      {%- when 'bad' -%}×
                      {%- else -%}{{ block.settings.own_text }}
                    {%- endcase -%}
                  </span>
                  {%- if block.settings.own_note != blank -%}
                    <span class="alsel-competitor-comparison__note">{{ block.settings.own_note }}</span>
                  {%- endif -%}
                </td>
                {%- if section.settings.col2_label != blank -%}
                  <td class="alsel-competitor-comparison__cell">
                    <span class="alsel-competitor-comparison__mark alsel-competitor-comparison__mark--{{ block.settings.col2_mark }}">
                      {%- case block.settings.col2_mark -%}
                        {%- when 'best' -%}◎
                        {%- when 'good' -%}○
                        {%- when 'fair' -%}△
                        {%- when 'bad' -%}×
                        {%- else -%}{{ block.settings.col2_text }}
                      {%- endcase -%}
                    </span>
                  </td>
                {%- endif -%}
                {%- if section.settings.col3_label != blank -%}
                  <td class="alsel-competitor-comparison__cell">
                    <span class="alsel-competitor-comparison__mark alsel-competitor-comparison__mark--{{ block.settings.col3_mark }}">
                      {%- case block.settings.col3_mark -%}
                        {%- when 'best' -%}◎
                        {%- when 'good' -%}○
                        {%- when 'fair' -%}△
                        {%- when 'bad' -%}×
                        {%- else -%}{{ block.settings.col3_text }}
                      {%- endcase -%}
                    </span>
                  </td>
                {%- endif -%}
              </tr>
            {%- endfor -%}
          </tbody>
        </table>
      </div>

      {%- if section.settings.note != blank -%}
        <p class="alsel-competitor-comparison__footer-note">{{ section.settings.note }}</p>
      {%- endif -%}

      {%- if section.settings.cta_text != blank and section.settings.cta_link != blank -%}
        <div class="alsel-competitor-comparison__cta-wrap">
          <a class="alsel-competitor-comparison__cta" href="{{ section.settings.cta_link }}">
            {{ section.settings.cta_text }}
          </a>
        </div>
      {%- endif -%}
    {%- endif -%}
  </div>
</section>

<style>
  .alsel-competitor-comparison { padding: 3rem 1rem; background: {{ section.settings.bg_color }}; }
  .alsel-competitor-comparison__inner { max-width: 1000px; margin: 0 auto; }
  .alsel-competitor-comparison__heading { font-size: clamp(1.4rem, 4vw, 2.2rem); text-align: center; margin: 0 0 0.75rem; color: {{ section.settings.text_color }}; font-weight: 700; }
  .alsel-competitor-comparison__sub { text-align: center; font-size: 0.95rem; line-height: 1.7; color: {{ section.settings.text_color }}; opacity: 0.85; margin: 0 0 2rem; }
  .alsel-competitor-comparison__empty { text-align: center; color: #888; padding: 2rem 0; }
  .alsel-competitor-comparison__scroll { overflow-x: auto; -webkit-overflow-scrolling: touch; border-radius: 12px; background: #fff; box-shadow: 0 2px 12px rgba(0,0,0,0.06); }
  .alsel-competitor-comparison__table { width: 100%; min-width: 480px; border-collapse: collapse; font-size: 0.9rem; }
  .alsel-competitor-comparison__th { padding: 1rem 0.75rem; text-align: center; font-weight: 700; background: #f1f5f9; color: #334155; border-bottom: 2px solid #e2e8f0; vertical-align: middle; }
  .alsel-competitor-comparison__th--item { text-align: left; min-width: 110px; }
  .alsel-competitor-comparison__th--own { background: {{ section.settings.own_color }}; color: #fff; position: relative; }
  .alsel-competitor-comparison__badge { display: inline-block; background: #fff; color: {{ section.settings.own_color }}; font-size: 0.7rem; padding: 0.15rem 0.6rem; border-radius: 9999px; margin-right: 0.4rem; font-weight: 700; }
  .alsel-competitor-comparison__col-label { display: inline-block; vertical-align: middle; }
  .alsel-competitor-comparison__row-head { padding: 1rem 0.75rem; text-align: left; font-weight: 600; background: #f8fafc; color: #1e293b; border-bottom: 1px solid #e2e8f0; vertical-align: middle; }
  .alsel-competitor-comparison__cell { padding: 1rem 0.75rem; text-align: center; border-bottom: 1px solid #e2e8f0; vertical-align: middle; }
  .alsel-competitor-comparison__cell--own { background: {{ section.settings.own_color }}0d; }
  .alsel-competitor-comparison__mark { display: inline-block; font-size: 1.3rem; font-weight: 700; line-height: 1; }
  .alsel-competitor-comparison__mark--best { color: {{ section.settings.own_color }}; font-size: 1.6rem; }
  .alsel-competitor-comparison__mark--good { color: #16a34a; }
  .alsel-competitor-comparison__mark--fair { color: #f59e0b; }
  .alsel-competitor-comparison__mark--bad { color: #94a3b8; }
  .alsel-competitor-comparison__mark--text { font-size: 0.9rem; }
  .alsel-competitor-comparison__note { display: block; font-size: 0.75rem; color: #64748b; margin-top: 0.25rem; line-height: 1.4; }
  .alsel-competitor-comparison__footer-note { font-size: 0.8rem; color: #64748b; margin: 1rem 0 0; text-align: center; line-height: 1.6; }
  .alsel-competitor-comparison__cta-wrap { text-align: center; margin-top: 2rem; }
  .alsel-competitor-comparison__cta { display: inline-block; padding: 1rem 2.5rem; background: {{ section.settings.own_color }}; color: #fff; text-decoration: none; border-radius: 9999px; font-weight: 700; font-size: 1rem; transition: opacity 0.2s; }
  .alsel-competitor-comparison__cta:hover { opacity: 0.85; }
  @media (min-width: 750px) {
    .alsel-competitor-comparison { padding: 5rem 2rem; }
    .alsel-competitor-comparison__table { font-size: 1rem; }
    .alsel-competitor-comparison__th, .alsel-competitor-comparison__cell, .alsel-competitor-comparison__row-head { padding: 1.25rem 1rem; }
  }
</style>

{% schema %}
{
