    { "type": "text", "id": "col3_label", "label": "他社 B 列のラベル", "default": "一般的な商品 B", "info": "空欄にするとこの列は非表示になります" },
    { "type": "header", "content": "色設定" },
    { "type": "color", "id": "bg_color", "label": "背景色", "default": "#f8fafc" },
