        { "type": "header", "content": "他社 A の評価" },
        { "type": "select", "id": "col2_mark", "label": "評価マーク",
          "options": [
            { "value": "best", "label": "◎ 非常に良い" },
            { "value": "good", "label": "○ 良い" },
            { "value": "fair", "label": "△ 普通" },
            { "value": "bad", "label": "× 弱い" },
            { "value": "text", "label": "自由入力テキスト" }
          ],
          "default": "fair" },
        { "type": "text", "id": "col2_text", "label": "自由入力テキスト" },
        { "type": "header", "content": "他社 B の評価" },
        { "type": "select", "id": "col3_mark", "label": "評価マーク",
          "options": [
            { "value": "best", "label": "◎ 非常に良い" },
            { "value": "good", "label": "○ 良い" },
            { "value": "fair", "label": "△ 普通" },
            { "value": "bad", "label": "× 弱い" },
            { "value": "text", "label": "自由入力テキスト" }
          ],
          "default": "bad" },
        { "type": "text", "id": "col3_text", "label": "自由入力テキスト" }
      ]
    }
  ],
