    background: linear-gradient(135deg, color-mix(in srgb, var(--accent) 15%, #fff), color-mix(in srgb, var(--accent) 5%, #fff));
    display: flex; align-items: center; justify-content: center;
  }
  .alsel-concern-guide__image { width: 100%; height: 100%; object-fit: cover; display: block; }
  .alsel-concern-guide__icon { font-size: clamp(3rem, 8vw, 4.5rem); }
  .alsel-concern-guide__label {
    position: absolute; top: 0.75rem; left: 0.75rem;
