  }
  .alsel-concern-guide__arrow { transition: transform 0.2s ease; }
  .alsel-concern-guide__card:hover .alsel-concern-guide__arrow { transform: translateX(4px); }

  @media (min-width: 600px) {
    .alsel-concern-guide__grid { grid-template-columns: repeat(2, 1fr); gap: 1.25rem; }
  }
  @media (min-width: 750px) {
    .alsel-concern-guide { padding: 5rem 2rem; }
    .alsel-concern-guide__grid[data-cols-pc="3"] { grid-template-columns: repeat(3, 1fr); }
    .alsel-concern-guide__grid[data-cols-pc="4"] { grid-template-columns: repeat(4, 1fr); }
    .alsel-concern-guide__grid { gap: 1.5rem; }
  }
</style>

