<section class="alsel-countdown-timer" aria-label="{{ section.settings.heading | escape }}">
  <div class="alsel-countdown-timer__inner">
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-countdown-timer__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="alsel-countdown-timer__sub">{{ section.settings.subheading }}</p>
    {%- endif -%}

    {%- assign end_year = section.settings.end_year -%}
    {%- assign end_month = section.settings.end_month -%}
    {%- assign end_day = section.settings.end_day -%}
    {%- assign end_hour = section.settings.end_hour -%}
    {%- assign end_minute = section.settings.end_minute -%}

    <div
      class="alsel-countdown-timer__timer"
      data-alsel-countdown
      data-year="{{ end_year }}"
      data-month="{{ end_month }}"
      data-day="{{ end_day }}"
      data-hour="{{ end_hour }}"
      data-minute="{{ end_minute }}"
      role="timer"
      aria-live="polite"
    >
      <div class="alsel-countdown-timer__unit">
        <span class="alsel-countdown-timer__num" data-days>00</span>
        <span class="alsel-countdown-timer__label">日</span>
      </div>
      <span class="alsel-countdown-timer__colon" aria-hidden="true">:</span>
      <div class="alsel-countdown-timer__unit">
        <span class="alsel-countdown-timer__num" data-hours>00</span>
        <span class="alsel-countdown-timer__label">時間</span>
      </div>
      <span class="alsel-countdown-timer__colon" aria-hidden="true">:</span>
      <div class="alsel-countdown-timer__unit">
        <span class="alsel-countdown-timer__num" data-minutes>00</span>
        <span class="alsel-countdown-timer__label">分</span>
      </div>
      <span class="alsel-countdown-timer__colon" aria-hidden="true">:</span>
      <div class="alsel-countdown-timer__unit">
        <span class="alsel-countdown-timer__num" data-seconds>00</span>
        <span class="alsel-countdown-timer__label">秒</span>
      </div>
    </div>

    <p class="alsel-countdown-timer__ended" data-alsel-countdown-ended hidden>
      {{ section.settings.ended_text | escape }}
    </p>

    {%- if section.settings.cta_text != blank and section.settings.cta_link != blank -%}
      <a class="alsel-countdown-timer__cta" href="{{ section.settings.cta_link }}">
        {{ section.settings.cta_text }}
      </a>
    {%- endif -%}
  </div>
</section>

<style>
  .alsel-countdown-timer {
    background: {{ section.settings.bg_color }};
    color: {{ section.settings.text_color }};
    padding: 2.5rem 1rem;
  }
  .alsel-countdown-timer__inner {
    max-width: 880px;
    margin: 0 auto;
    text-align: center;
  }
  .alsel-countdown-timer__heading {
    font-size: clamp(1.3rem, 4vw, 2rem);
    font-weight: 700;
    margin: 0 0 0.5rem;
