    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.4rem;
    flex-wrap: nowrap;
  }
  .alsel-countdown-timer__unit {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 56px;
  }
  .alsel-countdown-timer__num {
    display: inline-block;
    background: {{ section.settings.num_bg_color }};
    color: {{ section.settings.num_text_color }};
    font-size: clamp(1.4rem, 5vw, 2.4rem);
    font-weight: 700;
