    font-variant-numeric: tabular-nums;
    letter-spacing: 0.05em;
  }
  .alsel-countdown-timer__label {
    font-size: 0.75rem;
    margin-top: 0.4rem;
    opacity: 0.8;
  }
  .alsel-countdown-timer__colon {
    font-size: clamp(1.2rem, 4vw, 2rem);
    font-weight: 700;
    align-self: flex-start;
    padding-top: 0.6rem;
    opacity: 0.6;
  }
  .alsel-countdown-timer__ended {
    font-size: 1.1rem;
    font-weight: 700;
    margin: 1.5rem 0 0;
  }
  .alsel-countdown-timer__cta {
    display: inline-block;
    margin-top: 1.5rem;
    padding: 0.9rem 2rem;
    background: {{ section.settings.cta_bg }};
