    .alsel-countdown-timer__timer {
      gap: 0.75rem;
    }
    .alsel-countdown-timer__unit {
      min-width: 88px;
    }
  }
</style>

<script>
  (function () {
    var root = document.currentScript.parentElement.querySelector('[data-alsel-countdown]');
    if (!root) return;
    var endedEl = document.currentScript.parentElement.querySelector('[data-alsel-countdown-ended]');
    var y = parseInt(root.dataset.year, 10);
    var mo = parseInt(root.dataset.month, 10) - 1;
    var d = parseInt(root.dataset.day, 10);
    var h = parseInt(root.dataset.hour, 10);
    var mi = parseInt(root.dataset.minute, 10);
    var target = new Date(y, mo, d, h, mi, 0).getTime();
    var daysEl = root.querySelector('[data-days]');
    var hoursEl = root.querySelector('[data-hours]');
    var minutesEl = root.querySelector('[data-minutes]');
    var secondsEl = root.querySelector('[data-seconds]');
    function pad(n) { return n < 10 ? '0' + n : '' + n; }
    function tick() {
      var diff = target - new Date().getTime();
      if (diff <= 0) {
        daysEl.textContent = '00';
        hoursEl.textContent = '00';
        minutesEl.textContent = '00';
        secondsEl.textContent = '00';
        root.setAttribute('hidden', '');
        if (endedEl) endedEl.removeAttribute('hidden');
        clearInterval(timer);
        return;
      }
      var s = Math.floor(diff / 1000);
      var days = Math.floor(s / 86400);
      var hours = Math.floor((s % 86400) / 3600);
      var minutes = Math.floor((s % 3600) / 60);
      var seconds = s % 60;
      daysEl.textContent = pad(days);
      hoursEl.textContent = pad(hours);
      minutesEl.textContent = pad(minutes);
      secondsEl.textContent = pad(seconds);
    }
    tick();
    var timer = setInterval(tick, 1000);
  })();
</script>

