<script>
  (function () {
    var section = document.currentScript.closest('.alsel-coupon-promotion') || document.querySelector('.alsel-coupon-promotion');
    if (!section) return;
    var buttons = section.querySelectorAll('.alsel-coupon-promotion__copy-btn');
    buttons.forEach(function (btn) {
      btn.addEventListener('click', function () {
        var targetId = btn.getAttribute('data-alsel-copy-target');
        var target = document.getElementById(targetId);
        if (!target) return;
        var text = target.textContent.trim();
        var copiedLabel = btn.getAttribute('data-alsel-copied-text') || 'コピーしました';
        var originalLabel = btn.getAttribute('data-alsel-copy-text') || 'コピー';
        var labelEl = btn.querySelector('.alsel-coupon-promotion__copy-btn-label');
        var done = function () {
          if (labelEl) labelEl.textContent = copiedLabel;
          btn.classList.add('is-copied');
          setTimeout(function () {
            if (labelEl) labelEl.textContent = originalLabel;
            btn.classList.remove('is-copied');
          }, 2000);
        };
        if (navigator.clipboard && navigator.clipboard.writeText) {
          navigator.clipboard.writeText(text).then(done).catch(function () {
            var ta = document.createElement('textarea');
            ta.value = text;
            document.body.appendChild(ta);
            ta.select();
            try { document.execCommand('copy'); done(); } catch (e) {}
            document.body.removeChild(ta);
          });
        } else {
          var ta = document.createElement('textarea');
          ta.value = text;
          document.body.appendChild(ta);
          ta.select();
          try { document.execCommand('copy'); done(); } catch (e) {}
          document.body.removeChild(ta);
        }
      });
    });
  })();
</script>

