{%- assign sec_heading = section.settings.heading | escape -%}

<section class="alsel-custom-order-steps" aria-label="{{ sec_heading }}">
  <div class="alsel-custom-order-steps__inner">
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-custom-order-steps__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.lead != blank -%}
      <p class="alsel-custom-order-steps__lead">{{ section.settings.lead }}</p>
    {%- endif -%}

    {%- if section.blocks.size == 0 -%}
      <p class="alsel-custom-order-steps__empty">
        手順はまだ登録されていません。テーマエディタからブロックを追加してください。
      </p>
    {%- else -%}
      <ol class="alsel-custom-order-steps__list">
        {%- for block in section.blocks -%}
          {%- assign block_alt = block.settings.title | escape -%}
          <li class="alsel-custom-order-steps__item" {{ block.shopify_attributes }}>
            <div class="alsel-custom-order-steps__num" aria-hidden="true">
              <span class="alsel-custom-order-steps__num-label">STEP</span>
              <span class="alsel-custom-order-steps__num-value">{{ forloop.index }}</span>
            </div>
            <div class="alsel-custom-order-steps__card">
              {%- if block.settings.icon != blank -%}
                {{ block.settings.icon | image_url: width: 200 | image_tag: loading: 'lazy', class: 'alsel-custom-order-steps__icon', alt: block_alt, widths: '100, 150, 200' }}
              {%- endif -%}
              <div class="alsel-custom-order-steps__body">
                {%- if block.settings.duration != blank -%}
                  <span class="alsel-custom-order-steps__duration">目安:{{ block.settings.duration }}</span>
                {%- endif -%}
                <h3 class="alsel-custom-order-steps__title">{{ block.settings.title }}</h3>
                <p class="alsel-custom-order-steps__text">{{ block.settings.body }}</p>
              </div>
            </div>
          </li>
        {%- endfor -%}
      </ol>
    {%- endif -%}

    {%- if section.settings.note != blank -%}
      <div class="alsel-custom-order-steps__note">
        <p>{{ section.settings.note }}</p>
      </div>
    {%- endif -%}

    {%- if section.settings.cta_text != blank and section.settings.cta_link != blank -%}
      <div class="alsel-custom-order-steps__cta-wrap">
        <a class="alsel-custom-order-steps__cta" href="{{ section.settings.cta_link }}">
          {{ section.settings.cta_text }}
        </a>
      </div>
    {%- endif -%}
  </div>
</section>

<style>
  .alsel-custom-order-steps {
    --accent: {{ section.settings.accent_color }};
    --bg: {{ section.settings.bg_color }};
    --card-bg: #ffffff;
    --text: #1f2937;
    --muted: #64748b;
    background: var(--bg);
