    grid-template-columns: 64px 1fr;
    gap: 0.75rem;
    align-items: stretch;
    position: relative;
  }
  .alsel-custom-order-steps__item:not(:last-child)::after {
    content: "";
    position: absolute;
    left: 31px;
    top: 64px;
    bottom: -1.25rem;
    width: 2px;
    background: var(--accent);
    opacity: 0.25;
  }
  .alsel-custom-order-steps__num {
    width: 64px;
    height: 64px;
    border-radius: 50%;
    background: var(--accent);
    color: #fff;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }
  .alsel-custom-order-steps__num-label {
