    height: 56px;
    object-fit: contain;
    flex-shrink: 0;
  }
  .alsel-custom-order-steps__body { flex: 1; min-width: 0; }
  .alsel-custom-order-steps__duration {
    display: inline-block;
    font-size: 0.75rem;
    font-weight: 700;
    color: var(--accent);
    background: rgba(0,0,0,0.04);
    padding: 0.2rem 0.6rem;
    border-radius: 9999px;
    margin: 0 0 0.5rem;
  }
  .alsel-custom-order-steps__title {
    font-size: 1.05rem;
    font-weight: 700;
    margin: 0 0 0.5rem;
    line-height: 1.4;
  }
  .alsel-custom-order-steps__text {
    font-size: 0.9rem;
    line-height: 1.8;
    color: var(--muted);
    margin: 0;
  }
  .alsel-custom-order-steps__note {
    margin-top: 2rem;
    padding: 1rem 1.25rem;
    background: rgba(0,0,0,0.03);
    border-left: 3px solid var(--accent);
    border-radius: 4px;
    font-size: 0.85rem;
    line-height: 1.8;
    color: var(--muted);
  }
  .alsel-custom-order-steps__note p { margin: 0; }
  .alsel-custom-order-steps__cta-wrap { text-align: center; margin-top: 2rem; }
  .alsel-custom-order-steps__cta {
    display: inline-block;
    padding: 0.95rem 2.5rem;
    background: var(--accent);
    color: #fff;
    text-decoration: none;
    border-radius: 9999px;
    font-weight: 700;
    font-size: 0.95rem;
  }
  @media (min-width: 750px) {
    .alsel-custom-order-steps { padding: 5rem 2rem; }
    .alsel-custom-order-steps__item { grid-template-columns: 80px 1fr; gap: 1.25rem; }
