    .alsel-custom-order-steps__num { width: 80px; height: 80px; }
    .alsel-custom-order-steps__num-value { font-size: 1.75rem; }
    .alsel-custom-order-steps__card { padding: 1.5rem 1.75rem; }
    .alsel-custom-order-steps__icon { width: 72px; height: 72px; }
    .alsel-custom-order-steps__title { font-size: 1.15rem; }
  }
</style>

