    --alsel-faq-text: {{ section.settings.text_color }};
    --alsel-faq-accent: {{ section.settings.accent_color }};
    --alsel-faq-card: {{ section.settings.card_color }};
    --alsel-faq-border: {{ section.settings.border_color }};
    background: var(--alsel-faq-bg);
