      {%- assign alt_1 = section.settings.heading | escape -%}
{{ section.settings.image_mobile
        | image_url: width: 1000
        | image_tag:
          loading: 'eager',
          fetchpriority: 'high',
          class: 'alsel-hero-fv-lp__img alsel-hero-fv-lp__img--mobile',
