  <div class="alsel-image-only-lp__inner{% if section.settings.full_width %} alsel-image-only-lp__inner--full{% endif %}">

    {%- if section.blocks.size == 0 -%}
      <p class="alsel-image-only-lp__empty">
        現在表示できるLP画像はありません。テーマエディタからLP画像ブロックを追加してください。
      </p>
    {%- endif -%}

    {%- for block in section.blocks -%}
      {%- assign img_alt = block.settings.image_alt | default: '商品紹介画像' | escape -%}
      <div class="alsel-image-only-lp__item" {{ block.shopify_attributes }}>
        {%- if block.settings.lp_image != blank -%}
          {%- if block.settings.link_url != blank -%}
            <a class="alsel-image-only-lp__link" href="{{ block.settings.link_url }}" aria-label="{{ img_alt }}の詳細を見る">
          {%- endif -%}
          {%- if forloop.first -%}
            {{ block.settings.lp_image | image_url: width: 1500 | image_tag:
              loading: 'eager',
              fetchpriority: 'high',
              class: 'alsel-image-only-lp__image',
              alt: img_alt,
              widths: '375, 550, 750, 1100, 1500',
              sizes: '(min-width: 750px) 750px, 100vw' }}
          {%- else -%}
            {{ block.settings.lp_image | image_url: width: 1500 | image_tag:
              loading: 'lazy',
              class: 'alsel-image-only-lp__image',
              alt: img_alt,
              widths: '375, 550, 750, 1100, 1500',
              sizes: '(min-width: 750px) 750px, 100vw' }}
          {%- endif -%}
          {%- if block.settings.link_url != blank -%}
            </a>
          {%- endif -%}
        {%- else -%}
          <div class="alsel-image-only-lp__placeholder">
            <span>LP画像をアップロードしてください</span>
          </div>
        {%- endif -%}
      </div>
    {%- endfor -%}

    {%- if section.settings.cta_text != blank and section.settings.cta_link != blank -%}
      <div class="alsel-image-only-lp__cta-wrap">
        <a class="alsel-image-only-lp__cta" href="{{ section.settings.cta_link }}">
          <span class="alsel-image-only-lp__cta-arrow">▶</span>
          {{ section.settings.cta_text }}
        </a>
        {%- if section.settings.cta_sub != blank -%}
          <p class="alsel-image-only-lp__cta-sub">{{ section.settings.cta_sub }}</p>
        {%- endif -%}
      </div>
    {%- endif -%}

  </div>
</section>

