  .alsel-image-text-alternate__text :where(p) { margin: 0 0 0.75rem; }
  .alsel-image-text-alternate__cta {
    display: inline-flex; align-items: center; gap: 0.5rem;
    background: var(--accent); color: #fff;
    padding: 0.9rem 1.6rem; border-radius: 9999px;
    text-decoration: none; font-weight: 700; font-size: 1rem;
    box-shadow: 0 3px 0 rgba(0,0,0,0.2);
    transition: transform 0.15s;
  }
  .alsel-image-text-alternate__cta:hover { transform: translateY(-2px); }
  .alsel-image-text-alternate__cta-arrow { font-size: 0.7rem; }
  .alsel-image-text-alternate__bottom {
    text-align: center; max-width: 900px; margin: 2.5rem auto 0;
    font-size: 1.1rem; font-weight: 700; color: var(--accent);
  }
  @media (min-width: 750px) {
    .alsel-image-text-alternate { padding: 5rem 2rem; }
    .alsel-image-text-alternate__row {
      grid-template-columns: 1fr 1fr;
      gap: 2.5rem;
      padding: 2rem;
      align-items: center;
    }
    .alsel-image-text-alternate__row--reverse .alsel-image-text-alternate__media { order: 2; }
    .alsel-image-text-alternate__row--reverse .alsel-image-text-alternate__body { order: 1; }
    .alsel-image-text-alternate__number { width: 80px; height: 80px; top: -16px; left: -16px; }
    .alsel-image-text-alternate__number strong { font-size: 1.6rem; }
  }
</style>

