<script>
  (function() {
    var root = document.querySelector('.alsel-limited-sale-banner__countdown');
    if (!root) return;
    var endTs = parseInt(root.getAttribute('data-end'), 10) * 1000;
    var dEl = root.querySelector('[data-days]');
    var hEl = root.querySelector('[data-hours]');
    var mEl = root.querySelector('[data-mins]');
    var sEl = root.querySelector('[data-secs]');
    function pad(n) { return n < 10 ? '0' + n : '' + n; }
    function tick() {
      var diff = endTs - Date.now();
      if (diff <= 0) { dEl.textContent = '00'; hEl.textContent = '00'; mEl.textContent = '00'; sEl.textContent = '00'; return; }
      var d = Math.floor(diff / 86400000);
      var h = Math.floor((diff % 86400000) / 3600000);
      var m = Math.floor((diff % 3600000) / 60000);
      var s = Math.floor((diff % 60000) / 1000);
      dEl.textContent = pad(d); hEl.textContent = pad(h); mEl.textContent = pad(m); sEl.textContent = pad(s);
    }
    tick();
    setInterval(tick, 1000);
  })();
</script>

