          class="alsel-lookbook__item"
          {% if block.settings.link != blank %}href="{{ block.settings.link }}" aria-label="{{ look_alt }}のページへ"{% endif %}
          {{ block.shopify_attributes }}
        >
          <figure class="alsel-lookbook__figure">
            {%- if block.settings.image != blank -%}
              {{ block.settings.image
                | image_url: width: 1200
                | image_tag:
                  loading: 'lazy',
                  class: 'alsel-lookbook__image',
                  alt: look_alt,
                  widths: '375, 600, 800, 1000, 1200',
                  sizes: '(min-width: 750px) 50vw, 100vw' }}
            {%- else -%}
              <div class="alsel-lookbook__placeholder" aria-hidden="true">IMAGE</div>
            {%- endif -%}
            {%- if block.settings.badge != blank -%}
              <span class="alsel-lookbook__badge">{{ block.settings.badge }}</span>
            {%- endif -%}
          </figure>
          {%- if block.settings.title != blank or block.settings.caption != blank -%}
            <figcaption class="alsel-lookbook__caption">
              {%- if block.settings.title != blank -%}
                <h3 class="alsel-lookbook__title">{{ block.settings.title }}</h3>
              {%- endif -%}
              {%- if block.settings.caption != blank -%}
                <p class="alsel-lookbook__text">{{ block.settings.caption }}</p>
              {%- endif -%}
              {%- if block.settings.link != blank and block.settings.link_text != blank -%}
                <span class="alsel-lookbook__more">{{ block.settings.link_text }}<span aria-hidden="true"> →</span></span>
              {%- endif -%}
            </figcaption>
          {%- endif -%}
        </{{ tag }}>
      {%- endfor -%}
    </div>
  {%- endif -%}
</section>

