              <span class="alsel-lp-table-of-contents__arrow" aria-hidden="true">▼</span>
            </a>
          </li>
        {%- endfor -%}
      </ol>
    {%- endif -%}

    {%- if s.footnote != blank -%}
      <p class="alsel-lp-table-of-contents__footnote">{{ s.footnote }}</p>
    {%- endif -%}
  </div>
