  }
  .alsel-problem-checklist__inner { text-align: center; }
  .alsel-problem-checklist__heading {
    font-size: clamp(1.5rem, 5vw, 2.4rem);
    font-weight: 700;
    color: var(--text);
    margin: 0 0 1rem;
    line-height: 1.5;
    position: relative;
    display: inline-block;
    padding: 0 1.5rem;
  }
  .alsel-problem-checklist__heading::before,
