    content: '';
    position: absolute;
    bottom: 0;
    width: 3px;
    height: 80%;
    background: var(--text);
  }
  .alsel-problem-checklist__heading::before { left: 0; transform: rotate(-20deg); }
  .alsel-problem-checklist__heading::after { right: 0; transform: rotate(20deg); }
  .alsel-problem-checklist__heading-inner mark,
  .alsel-problem-checklist__mark {
    background: linear-gradient(transparent 60%, {{ section.settings.marker_color }} 60%);
    color: inherit;
    padding: 0 0.1em;
  }
  .alsel-problem-checklist__sub {
    font-size: 1rem;
    color: var(--text);
    margin: 0 0 2rem;
    line-height: 1.7;
  }
  .alsel-problem-checklist__list {
    background: #fff;
    border: 3px solid var(--text);
    border-radius: 12px;
    padding: 1.5rem 1.2rem;
    text-align: left;
    box-shadow: 6px 6px 0 var(--accent);
  }
  .alsel-problem-checklist__item {
    display: flex;
    align-items: flex-start;
    gap: 0.9rem;
    padding: 0.9rem 0;
    border-bottom: 1px dashed #d4d4d8;
    font-size: 1.05rem;
    line-height: 1.6;
    color: var(--text);
  }
  .alsel-problem-checklist__item:last-child { border-bottom: none; }
  .alsel-problem-checklist__check {
    flex-shrink: 0;
    width: 28px;
    height: 28px;
    border: 3px solid var(--accent);
    border-radius: 6px;
    position: relative;
    background: #fff;
    margin-top: 2px;
  }
  .alsel-problem-checklist__check::after {
    content: '';
    position: absolute;
    left: 6px;
    top: 1px;
    width: 9px;
    height: 16px;
    border-right: 4px solid var(--accent);
    border-bottom: 4px solid var(--accent);
    transform: rotate(45deg);
  }
  .alsel-problem-checklist__text { flex: 1; font-weight: 600; }
  .alsel-problem-checklist__closing {
    margin-top: 2.5rem;
    position: relative;
    padding-top: 2.5rem;
  }
  .alsel-problem-checklist__closing-arrow {
    position: absolute;
    top: 0;
    left: 50%;
    transform: translateX(-50%);
    width: 0;
    height: 0;
    border-left: 30px solid transparent;
    border-right: 30px solid transparent;
    border-top: 28px solid var(--accent);
  }
  .alsel-problem-checklist__closing-text {
    display: inline-block;
    background: var(--accent);
    color: #fff;
    font-size: clamp(1.1rem, 3.5vw, 1.6rem);
    font-weight: 700;
    padding: 1rem 2rem;
    border-radius: 9999px;
    margin: 0;
    box-shadow: 4px 4px 0 var(--accent-sub);
    line-height: 1.4;
  }
  @media (min-width: 750px) {
    .alsel-problem-checklist { padding: 5rem 2rem; }
    .alsel-problem-checklist__list { padding: 2rem 2.5rem; }
    .alsel-problem-checklist__item { font-size: 1.15rem; padding: 1.1rem 0; gap: 1.2rem; }
  }
</style>

