  .alsel-product-finder-quiz__product { text-align: center; }
  .alsel-product-finder-quiz__pimg { width: 100%; max-width: 280px; aspect-ratio: 1 / 1; object-fit: cover; border-radius: 12px; margin: 0 auto 1rem; display: block; }
  .alsel-product-finder-quiz__ptitle { font-size: 1.1rem; font-weight: 700; margin: 0 0 0.5rem; line-height: 1.4; }
  .alsel-product-finder-quiz__pdesc { font-size: 0.9rem; line-height: 1.7; color: #475569; margin: 0 0 1rem; }
  .alsel-product-finder-quiz__cta { display: inline-block; padding: 0.75rem 1.75rem; background: var(--pfq-accent); color: #fff; text-decoration: none; border-radius: 9999px; font-weight: 700; font-size: 0.95rem; transition: opacity 0.2s; }
  .alsel-product-finder-quiz__cta:hover { opacity: 0.85; }
  .alsel-product-finder-quiz__note { text-align: center; font-size: 0.85rem; color: #64748b; margin: 2rem 0 0; line-height: 1.6; }

  @media (min-width: 750px) {
    .alsel-product-finder-quiz { padding: 5rem 2rem; }
    .alsel-product-finder-quiz__grid { grid-template-columns: repeat(2, 1fr); gap: 2rem; }
    .alsel-product-finder-quiz__grid--three { grid-template-columns: repeat(3, 1fr); }
  }
  @media (min-width: 990px) {
    .alsel-product-finder-quiz__inner:has(.alsel-product-finder-quiz__card:nth-child(3)) .alsel-product-finder-quiz__grid { grid-template-columns: repeat(3, 1fr); }
    .alsel-product-finder-quiz__inner:has(.alsel-product-finder-quiz__card:nth-child(4)) .alsel-product-finder-quiz__grid { grid-template-columns: repeat(4, 1fr); }
  }
</style>

