    <div class="alsel-product-mini-lp__band">
      <span class="alsel-product-mini-lp__band-text">{{ section.settings.top_band_text }}</span>
    </div>
  {%- endif -%}

  <div class="alsel-product-mini-lp__hero">
    {%- if section.settings.main_image != blank -%}
      {{ section.settings.main_image | image_url: width: 1200 | image_tag: loading: 'lazy', class: 'alsel-product-mini-lp__hero-img', alt: main_alt, widths: '375, 750, 1100, 1200' }}
    {%- endif -%}
    <div class="alsel-product-mini-lp__hero-inner">
      {%- if section.settings.sub_heading != blank -%}
        <p class="alsel-product-mini-lp__sub">{{ section.settings.sub_heading }}</p>
      {%- endif -%}
      {%- if section.settings.main_heading != blank -%}
        <h2 class="alsel-product-mini-lp__title">{{ section.settings.main_heading }}</h2>
      {%- endif -%}
      {%- if section.settings.lead_text != blank -%}
        <p class="alsel-product-mini-lp__lead">{{ section.settings.lead_text }}</p>
      {%- endif -%}
    </div>
  </div>

  {%- if section.blocks.size == 0 -%}
    <p class="alsel-product-mini-lp__empty" style="text-align:center;color:#888;padding:2rem 0;">
      訴求ブロックはまだ登録されていません。テーマエディタから追加してください。
    </p>
  {%- endif -%}

  {%- for block in section.blocks -%}
    {%- case block.type -%}

    {%- when 'point' -%}
      {%- assign point_alt = block.settings.title | escape -%}
      <article class="alsel-product-mini-lp__point" {{ block.shopify_attributes }}>
        <div class="alsel-product-mini-lp__point-num">POINT {{ forloop.index }}</div>
        {%- if block.settings.image != blank -%}
          {{ block.settings.image | image_url: width: 800 | image_tag: loading: 'lazy', class: 'alsel-product-mini-lp__point-img', alt: point_alt, widths: '375, 750, 800' }}
        {%- endif -%}
        <div class="alsel-product-mini-lp__point-body">
          {%- if block.settings.title != blank -%}
            <h3 class="alsel-product-mini-lp__point-title">{{ block.settings.title }}</h3>
          {%- endif -%}
          {%- if block.settings.text != blank -%}
            <div class="alsel-product-mini-lp__point-text">{{ block.settings.text }}</div>
          {%- endif -%}
        </div>
      </article>

    {%- when 'voice' -%}
      <article class="alsel-product-mini-lp__voice" {{ block.shopify_attributes }}>
        <div class="alsel-product-mini-lp__voice-badge">お客様の声</div>
        <div class="alsel-product-mini-lp__voice-stars">★★★★★</div>
        {%- if block.settings.comment != blank -%}
          <p class="alsel-product-mini-lp__voice-comment">{{ block.settings.comment }}</p>
        {%- endif -%}
        {%- if block.settings.name != blank -%}
          <p class="alsel-product-mini-lp__voice-name">{{ block.settings.name }}</p>
        {%- endif -%}
      </article>

    {%- when 'divider' -%}
      <div class="alsel-product-mini-lp__arrow" {{ block.shopify_attributes }} aria-hidden="true">▼</div>

    {%- endcase -%}
  {%- endfor -%}

  {%- if section.settings.cta_text != blank -%}
    <div class="alsel-product-mini-lp__cta-wrap">
      {%- if section.settings.cta_badge != blank -%}
        <span class="alsel-product-mini-lp__cta-badge">{{ section.settings.cta_badge }}</span>
      {%- endif -%}
      <a class="alsel-product-mini-lp__cta" href="{{ section.settings.cta_link | default: '#' }}">
        {{ section.settings.cta_text }}
        <span class="alsel-product-mini-lp__cta-arrow" aria-hidden="true">→</span>
      </a>
      {%- if section.settings.cta_note != blank -%}
        <p class="alsel-product-mini-lp__cta-note">{{ section.settings.cta_note }}</p>
      {%- endif -%}
    </div>
  {%- endif -%}

</section>

