    {%- endif -%}

    {%- if ranking_products.size > 0 -%}
      <div class="alsel-ranking-top-three__grid">
        {%- for product in ranking_products -%}
          {%- if forloop.index > 3 -%}{%- break -%}{%- endif -%}
          {%- assign rank = forloop.index -%}
          {%- assign alt_text = product.title | escape -%}
          {%- assign product_image = product.featured_image -%}

          {%- case rank -%}
            {%- when 1 -%}
              {%- assign rank_class = 'is-first' -%}
              {%- assign rank_label = '1位' -%}
              {%- assign medal = section.settings.medal_first -%}
            {%- when 2 -%}
              {%- assign rank_class = 'is-second' -%}
              {%- assign rank_label = '2位' -%}
              {%- assign medal = section.settings.medal_second -%}
            {%- when 3 -%}
              {%- assign rank_class = 'is-third' -%}
              {%- assign rank_label = '3位' -%}
              {%- assign medal = section.settings.medal_third -%}
