  .alsel-related-products__scroller::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.2); border-radius: 3px; }
  .alsel-related-products__card { scroll-snap-align: start; background: #fff; border-radius: {{ section.settings.card_radius }}px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.06); transition: transform 0.2s ease, box-shadow 0.2s ease; }
  .alsel-related-products__card:hover { transform: translateY(-3px); box-shadow: 0 6px 16px rgba(0,0,0,0.1); }
  .alsel-related-products__link { display: block; text-decoration: none; color: inherit; }
  .alsel-related-products__media { position: relative; aspect-ratio: 1 / 1; background: #f3f4f6; overflow: hidden; }
  .alsel-related-products__image { width: 100%; height: 100%; object-fit: cover; display: block; }
  .alsel-related-products__image--empty { display: flex; align-items: center; justify-content: center; color: #9ca3af; font-size: 0.9rem; }
  .alsel-related-products__badge { position: absolute; top: 0.5rem; left: 0.5rem; background: rgba(17,24,39,0.85); color: #fff; font-size: 0.7rem; font-weight: 700; padding: 0.25rem 0.6rem; border-radius: 4px; letter-spacing: 0.05em; }
  .alsel-related-products__body { padding: 0.85rem 0.9rem 1.1rem; }
  .alsel-related-products__title { font-size: 0.95rem; font-weight: 600; line-height: 1.5; margin: 0 0 0.5rem; color: {{ section.settings.text_color }}; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
  .alsel-related-products__price { margin: 0; font-size: 0.95rem; font-weight: 700; color: {{ section.settings.price_color }}; }
  .alsel-related-products__price-sale { color: #dc2626; margin-right: 0.5rem; }
