{% comment %}
============================================================
セクション名: 縦型ショート動画風
用途: TikTok や Instagram Reels のような縦長の動画カードを横一列に並べ、商品やブランドの世界観を動きで魅せるためのセクション
推奨設置場所: トップページの中段・商品詳細ページの下部・特集 LP の途中
カスタマイズポイント:
  - セクション見出し・サブ見出し
  - 各カードの動画ファイル(または動画 URL)・サムネイル画像
  - キャプション・ユーザー名・いいね数表示
  - カードのリンク先(商品ページや特集ページなど)
  - 背景色・文字色
  - ブロックの追加で動画カード数を調整(推奨 3〜8 枚)
注意点:
  - 動画は MP4(H.264)推奨。縦長 9:16(例: 720 × 1280px)で用意する
  - 動画は自動再生・ミュート・ループで表示される
  - サムネイル画像は動画読み込み前のプレースホルダとして利用される
  - ブロックが 0 個の場合はマーチャント向け案内が表示される
動作確認バージョン: Online Store 2.0
ライセンス: ALSEL Original
============================================================
{% endcomment %}

{%- assign sec_label = section.settings.heading | escape -%}

<section class="alsel-short-form-video" aria-label="{{ sec_label }}">
  <div class="alsel-short-form-video__head">
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-short-form-video__title">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="alsel-short-form-video__sub">{{ section.settings.subheading }}</p>
    {%- endif -%}
  </div>

  {%- if section.blocks.size == 0 -%}
    <p class="alsel-short-form-video__empty">
      表示できる動画はまだ登録されていません。テーマエディタから動画カードを追加してください。
    </p>
  {%- else -%}
    <div class="alsel-short-form-video__scroller" role="list">
      {%- for block in section.blocks -%}
        {%- assign cap = block.settings.caption | escape -%}
        <article class="alsel-short-form-video__card" role="listitem" {{ block.shopify_attributes }}>
          {%- if block.settings.link != blank -%}
            <a class="alsel-short-form-video__link" href="{{ block.settings.link }}" aria-label="{{ cap }}">
          {%- endif -%}

          <div class="alsel-short-form-video__media">
            {%- if block.settings.video != blank -%}
              <video
                class="alsel-short-form-video__video"
                src="{{ block.settings.video.sources[1].url | default: block.settings.video.sources[0].url }}"
                {%- if block.settings.poster != blank %} poster="{{ block.settings.poster | image_url: width: 720 }}"{%- endif -%}
                autoplay muted loop playsinline preload="metadata"></video>
            {%- elsif block.settings.video_url != blank -%}
              <video
                class="alsel-short-form-video__video"
                src="{{ block.settings.video_url }}"
                {%- if block.settings.poster != blank %} poster="{{ block.settings.poster | image_url: width: 720 }}"{%- endif -%}
                autoplay muted loop playsinline preload="metadata"></video>
            {%- elsif block.settings.poster != blank -%}
              {%- assign poster_alt = block.settings.caption | escape -%}
              {{ block.settings.poster | image_url: width: 720 | image_tag: loading: 'lazy', class: 'alsel-short-form-video__img', alt: poster_alt, widths: '360, 540, 720, 1080' }}
            {%- else -%}
              <div class="alsel-short-form-video__placeholder" aria-hidden="true">動画</div>
            {%- endif -%}

            <span class="alsel-short-form-video__badge" aria-hidden="true">▶</span>
          </div>

          <div class="alsel-short-form-video__overlay">
            {%- if block.settings.caption != blank -%}
              <p class="alsel-short-form-video__caption">{{ block.settings.caption }}</p>
            {%- endif -%}
            <div class="alsel-short-form-video__meta">
              {%- if block.settings.username != blank -%}
                <span class="alsel-short-form-video__user">@{{ block.settings.username }}</span>
              {%- endif -%}
              {%- if block.settings.likes != blank -%}
                <span class="alsel-short-form-video__likes">♥ {{ block.settings.likes }}</span>
              {%- endif -%}
            </div>
          </div>

          {%- if block.settings.link != blank -%}
            </a>
          {%- endif -%}
        </article>
      {%- endfor -%}
    </div>
  {%- endif -%}
</section>

<style>
  .alsel-short-form-video { padding: 3rem 1rem; background: {{ section.settings.bg_color }}; color: {{ section.settings.text_color }}; }
  .alsel-short-form-video__head { max-width: 1100px; margin: 0 auto 1.5rem; text-align: {{ section.settings.text_align }}; }
  .alsel-short-form-video__title { font-size: clamp(1.4rem, 4vw, 2rem); font-weight: 700; margin: 0 0 0.5rem; line-height: 1.3; }
  .alsel-short-form-video__sub { font-size: 0.95rem; line-height: 1.6; margin: 0; opacity: 0.8; }
  .alsel-short-form-video__empty { text-align: center; color: #888; padding: 2rem 0; }
  .alsel-short-form-video__scroller { display: flex; gap: 0.875rem; overflow-x: auto; overflow-y: hidden; padding: 0.5rem 0.25rem 1rem; scroll-snap-type: x mandatory; -webkit-overflow-scrolling: touch; scrollbar-width: thin; }
  .alsel-short-form-video__scroller::-webkit-scrollbar { height: 6px; }
  .alsel-short-form-video__scroller::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.2); border-radius: 3px; }
  .alsel-short-form-video__card { position: relative; flex: 0 0 auto; width: 60vw; max-width: 220px; aspect-ratio: 9 / 16; border-radius: 14px; overflow: hidden; scroll-snap-align: start; background: #111; box-shadow: 0 6px 18px rgba(0,0,0,0.18); transition: transform 0.25s ease; }
  .alsel-short-form-video__card:hover { transform: translateY(-4px); }
  .alsel-short-form-video__link { display: block; width: 100%; height: 100%; color: inherit; text-decoration: none; }
  .alsel-short-form-video__media { position: absolute; inset: 0; }
  .alsel-short-form-video__video,
  .alsel-short-form-video__img { width: 100%; height: 100%; object-fit: cover; display: block; }
  .alsel-short-form-video__placeholder { width: 100%; height: 100%; display: flex; align-items: center; justify-content: center; color: #fff; background: linear-gradient(135deg, #2c2c2c, #555); font-size: 0.9rem; letter-spacing: 0.1em; }
  .alsel-short-form-video__badge { position: absolute; top: 0.6rem; right: 0.6rem; width: 26px; height: 26px; border-radius: 50%; background: rgba(0,0,0,0.55); color: #fff; display: flex; align-items: center; justify-content: center; font-size: 0.7rem; }
  .alsel-short-form-video__overlay { position: absolute; left: 0; right: 0; bottom: 0; padding: 0.75rem 0.8rem; background: linear-gradient(to top, rgba(0,0,0,0.75), rgba(0,0,0,0)); color: #fff; }
  .alsel-short-form-video__caption { font-size: 0.85rem; line-height: 1.4; margin: 0 0 0.4rem; font-weight: 600; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
  .alsel-short-form-video__meta { display: flex; justify-content: space-between; align-items: center; font-size: 0.75rem; opacity: 0.95; }
  .alsel-short-form-video__user { font-weight: 600; }
  .alsel-short-form-video__likes { font-weight: 500; }
  @media (min-width: 750px) {
    .alsel-short-form-video { padding: 5rem 2rem; }
    .alsel-short-form-video__scroller { max-width: 1200px; margin: 0 auto; gap: 1.25rem; padding-bottom: 1.25rem; }
    .alsel-short-form-video__card { width: 220px; max-width: 240px; }
    .alsel-short-form-video__caption { font-size: 0.9rem; }
  }
</style>

