{%- assign root_class = 'alsel-size-guide-table' -%}
{%- assign img_alt = section.settings.guide_image_alt | default: 'サイズ採寸の図解' | escape -%}

<section class="{{ root_class }}{%- if section.settings.guide_image == blank %} {{ root_class }}--no-image{%- endif -%}" aria-label="{{ section.settings.heading | escape }}">
  <div class="{{ root_class }}__container">
    {%- if section.settings.category_label != blank -%}
      <span class="{{ root_class }}__category">{{ section.settings.category_label }}</span>
    {%- endif -%}
    {%- if section.settings.heading != blank -%}
      <h2 class="{{ root_class }}__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="{{ root_class }}__sub">{{ section.settings.subheading }}</p>
    {%- endif -%}

    <div class="{{ root_class }}__inner">
      <div class="{{ root_class }}__table-wrap" role="region" aria-label="サイズ比較表" tabindex="0">
        {%- if section.blocks.size == 0 -%}
          <p class="{{ root_class }}__empty">
            サイズの行はまだ登録されていません。テーマエディタからサイズ行を追加してください。
          </p>
        {%- else -%}
          <table class="{{ root_class }}__table">
            <thead>
              <tr>
                {%- if section.settings.col1 != blank -%}<th scope="col">{{ section.settings.col1 }}</th>{%- endif -%}
                {%- if section.settings.col2 != blank -%}<th scope="col">{{ section.settings.col2 }}</th>{%- endif -%}
                {%- if section.settings.col3 != blank -%}<th scope="col">{{ section.settings.col3 }}</th>{%- endif -%}
                {%- if section.settings.col4 != blank -%}<th scope="col">{{ section.settings.col4 }}</th>{%- endif -%}
                {%- if section.settings.col5 != blank -%}<th scope="col">{{ section.settings.col5 }}</th>{%- endif -%}
                {%- if section.settings.col6 != blank -%}<th scope="col">{{ section.settings.col6 }}</th>{%- endif -%}
              </tr>
            </thead>
            <tbody>
              {%- for block in section.blocks -%}
                <tr {{ block.shopify_attributes }} {%- if block.settings.highlight %} class="{{ root_class }}__row--highlight"{%- endif -%}>
                  {%- if section.settings.col1 != blank -%}<th scope="row">{{ block.settings.val1 }}</th>{%- endif -%}
                  {%- if section.settings.col2 != blank -%}<td>{{ block.settings.val2 }}</td>{%- endif -%}
                  {%- if section.settings.col3 != blank -%}<td>{{ block.settings.val3 }}</td>{%- endif -%}
                  {%- if section.settings.col4 != blank -%}<td>{{ block.settings.val4 }}</td>{%- endif -%}
                  {%- if section.settings.col5 != blank -%}<td>{{ block.settings.val5 }}</td>{%- endif -%}
                  {%- if section.settings.col6 != blank -%}<td>{{ block.settings.val6 }}</td>{%- endif -%}
                </tr>
              {%- endfor -%}
            </tbody>
          </table>
        {%- endif -%}
      </div>

      {%- if section.settings.guide_image != blank -%}
        <div class="{{ root_class }}__media">
          {{ section.settings.guide_image | image_url: width: 800 | image_tag: loading: 'lazy', class: root_class | append: '__image', alt: img_alt, widths: '375, 600, 800' }}
          {%- if section.settings.image_caption != blank -%}
            <p class="{{ root_class }}__caption">{{ section.settings.image_caption }}</p>
          {%- endif -%}
        </div>
      {%- endif -%}
    </div>

    {%- if section.settings.notice != blank -%}
      <p class="{{ root_class }}__notice">{{ section.settings.notice }}</p>
    {%- endif -%}
  </div>
</section>

