<section class="alsel-solution-section" aria-label="お悩み解決訴求">
  <div class="alsel-solution-section__inner">
    {%- if section.settings.eyebrow != blank -%}
      <p class="alsel-solution-section__eyebrow">{{ section.settings.eyebrow }}</p>
    {%- endif -%}
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-solution-section__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="alsel-solution-section__sub">{{ section.settings.subheading }}</p>
