        <span class="alsel-store-manager-pick__heading-mark">PICK UP</span>
        {{ section.settings.heading | escape }}
      </h2>
    {%- endif -%}

    <div class="alsel-store-manager-pick__layout">
      <div class="alsel-store-manager-pick__manager">
        {%- if section.settings.manager_image != blank -%}
          {%- assign alt_1 = section.settings.manager_name | escape -%}
{{ section.settings.manager_image
            | image_url: width: 400
            | image_tag: loading: 'lazy', class: 'alsel-store-manager-pick__avatar', alt: alt_1, widths: '200, 400' }}
        {%- else -%}
          <div class="alsel-store-manager-pick__avatar alsel-store-manager-pick__avatar--placeholder" aria-hidden="true">店長</div>
