        <p class="alsel-store-manager-pick__role">{{ section.settings.manager_role | escape }}</p>
        <p class="alsel-store-manager-pick__name">{{ section.settings.manager_name | escape }}</p>
      </div>

      <div class="alsel-store-manager-pick__bubble">
        <div class="alsel-store-manager-pick__comment">
          {{ section.settings.comment }}
        </div>
