      {%- assign product = section.settings.product -%}
      {%- if product != blank -%}
        <a class="alsel-store-manager-pick__product" href="{{ product.url }}" aria-label="{{ product.title | escape }}の商品ページへ">
          <div class="alsel-store-manager-pick__product-image-wrap">
            {%- if product.featured_image != blank -%}
              {%- assign alt_2 = product.title | escape -%}
{{ product.featured_image
                | image_url: width: 800
                | image_tag: loading: 'lazy', class: 'alsel-store-manager-pick__product-image', alt: alt_2, widths: '400, 600, 800' }}
            {%- endif -%}
            <span class="alsel-store-manager-pick__badge" aria-hidden="true">店長イチオシ</span>
