        <div class="alsel-store-manager-pick__product alsel-store-manager-pick__product--empty" aria-hidden="true">
          <p>テーマエディタから紹介商品をご選択ください。</p>
        </div>
      {%- endif -%}
    </div>
  </div>
</section>

