{%- assign sec_heading = section.settings.heading | escape -%}

<section
  class="alsel-swipe-banner"
  aria-label="{{ sec_heading | default: 'スワイプ型バナー' }}"
  data-autoplay="{{ section.settings.autoplay }}"
  data-interval="{{ section.settings.interval | times: 1000 }}"
>
  {%- if section.settings.heading != blank -%}
    <h2 class="alsel-swipe-banner__heading">{{ section.settings.heading }}</h2>
  {%- endif -%}

  {%- if section.settings.subheading != blank -%}
    <p class="alsel-swipe-banner__subheading">{{ section.settings.subheading }}</p>
  {%- endif -%}

  {%- if section.blocks.size == 0 -%}
    <p class="alsel-swipe-banner__empty">
      現在表示できるバナーはありません。テーマエディタからブロックを追加してください。
    </p>
  {%- else -%}
    <div class="alsel-swipe-banner__viewport">
      <ul class="alsel-swipe-banner__track" role="list">
        {%- for block in section.blocks -%}
          {%- assign alt_text = block.settings.title | default: '' | escape -%}
          <li class="alsel-swipe-banner__slide" {{ block.shopify_attributes }} aria-roledescription="スライド" aria-label="{{ forloop.index }} / {{ section.blocks.size }}">
            {%- if block.settings.link != blank -%}
              <a class="alsel-swipe-banner__link" href="{{ block.settings.link }}" aria-label="{{ alt_text | default: 'バナーを開く' }}">
            {%- endif -%}

            <div class="alsel-swipe-banner__media">
              {%- if block.settings.image != blank -%}
                {{ block.settings.image
                  | image_url: width: 1200
                  | image_tag:
                    loading: 'lazy',
                    class: 'alsel-swipe-banner__image',
                    alt: alt_text,
                    widths: '375, 600, 900, 1200',
                    sizes: '(min-width: 750px) 70vw, 90vw'
                }}
              {%- else -%}
                <div class="alsel-swipe-banner__placeholder" aria-hidden="true"></div>
              {%- endif -%}

              <div class="alsel-swipe-banner__caption alsel-swipe-banner__caption--{{ block.settings.text_position }}">
                {%- if block.settings.title != blank -%}
                  <p class="alsel-swipe-banner__title" style="color: {{ block.settings.text_color }};">{{ block.settings.title }}</p>
                {%- endif -%}
                {%- if block.settings.description != blank -%}
                  <p class="alsel-swipe-banner__desc" style="color: {{ block.settings.text_color }};">{{ block.settings.description }}</p>
                {%- endif -%}
                {%- if block.settings.button_text != blank -%}
                  <span class="alsel-swipe-banner__cta">{{ block.settings.button_text }}</span>
                {%- endif -%}
              </div>
            </div>

            {%- if block.settings.link != blank -%}
              </a>
            {%- endif -%}
          </li>
        {%- endfor -%}
      </ul>
    </div>

    {%- if section.settings.show_dots and section.blocks.size > 1 -%}
      <div class="alsel-swipe-banner__dots" role="tablist" aria-label="スライド切替">
        {%- for block in section.blocks -%}
          <button
            type="button"
            class="alsel-swipe-banner__dot"
            data-index="{{ forloop.index0 }}"
            aria-label="{{ forloop.index }} 枚目のバナーへ移動"
          ></button>
        {%- endfor -%}
      </div>
    {%- endif -%}
  {%- endif -%}
</section>

<style>
  .alsel-swipe-banner { background: {{ section.settings.bg_color }}; padding: 1.5rem 0; }
  .alsel-swipe-banner__heading { font-size: clamp(1.3rem, 4vw, 2rem); font-weight: 700; text-align: center; margin: 0 0 0.5rem; color: {{ section.settings.heading_color }}; padding: 0 1rem; }
  .alsel-swipe-banner__subheading { font-size: 0.95rem; line-height: 1.6; text-align: center; margin: 0 0 1.25rem; color: {{ section.settings.heading_color }}; padding: 0 1rem; opacity: 0.85; }
  .alsel-swipe-banner__empty { text-align: center; color: #888; padding: 2rem 1rem; margin: 0; }
  .alsel-swipe-banner__viewport { width: 100%; overflow: hidden; }
  .alsel-swipe-banner__track { display: flex; gap: 0.75rem; list-style: none; margin: 0; padding: 0 1rem; overflow-x: auto; scroll-snap-type: x mandatory; -webkit-overflow-scrolling: touch; scrollbar-width: none; }
  .alsel-swipe-banner__track::-webkit-scrollbar { display: none; }
  .alsel-swipe-banner__slide { flex: 0 0 88%; scroll-snap-align: center; border-radius: 14px; overflow: hidden; box-shadow: 0 4px 14px rgba(0,0,0,0.08); background: #fff; }
  .alsel-swipe-banner__link { display: block; color: inherit; text-decoration: none; }
  .alsel-swipe-banner__media { position: relative; aspect-ratio: 3 / 2; overflow: hidden; }
  .alsel-swipe-banner__image { width: 100%; height: 100%; object-fit: cover; display: block; }
  .alsel-swipe-banner__placeholder { width: 100%; height: 100%; background: linear-gradient(135deg, #e2e8f0, #cbd5e1); }
  .alsel-swipe-banner__caption { position: absolute; inset: 0; display: flex; flex-direction: column; justify-content: center; gap: 0.5rem; padding: 1.25rem; }
  .alsel-swipe-banner__caption--left { align-items: flex-start; text-align: left; }
  .alsel-swipe-banner__caption--center { align-items: center; text-align: center; }
  .alsel-swipe-banner__caption--right { align-items: flex-end; text-align: right; }
  .alsel-swipe-banner__caption--bottom-left { align-items: flex-start; justify-content: flex-end; text-align: left; }
  .alsel-swipe-banner__title { font-size: clamp(1.1rem, 4vw, 1.6rem); font-weight: 700; margin: 0; line-height: 1.4; text-shadow: 0 2px 8px rgba(0,0,0,0.25); }
  .alsel-swipe-banner__desc { font-size: 0.9rem; line-height: 1.5; margin: 0; text-shadow: 0 1px 6px rgba(0,0,0,0.25); }
  .alsel-swipe-banner__cta { display: inline-block; margin-top: 0.5rem; padding: 0.55rem 1.4rem; background: {{ section.settings.cta_bg }}; color: {{ section.settings.cta_color }}; border-radius: 9999px; font-size: 0.9rem; font-weight: 700; }
  .alsel-swipe-banner__dots { display: flex; justify-content: center; gap: 0.5rem; margin-top: 1rem; padding: 0 1rem; }
  .alsel-swipe-banner__dot { width: 8px; height: 8px; border-radius: 50%; border: none; background: {{ section.settings.dot_color }}; opacity: 0.4; cursor: pointer; padding: 0; transition: opacity 0.2s, transform 0.2s; }
  .alsel-swipe-banner__dot[aria-current="true"] { opacity: 1; transform: scale(1.4); }
  @media (min-width: 750px) {
    .alsel-swipe-banner { padding: 3rem 0; }
    .alsel-swipe-banner__track { gap: 1.25rem; padding: 0 2rem; max-width: {{ section.settings.max_width }}px; margin: 0 auto; }
    .alsel-swipe-banner__slide { flex: 0 0 {{ section.settings.pc_slide_percent }}%; }
    .alsel-swipe-banner__caption { padding: 2rem; }
  }
</style>

<script>
  (function(){
    const root = document.currentScript.previousElementSibling.previousElementSibling;
    if (!root || !root.classList.contains('alsel-swipe-banner')) return;
    const track = root.querySelector('.alsel-swipe-banner__track');
    const dots = root.querySelectorAll('.alsel-swipe-banner__dot');
    const slides = root.querySelectorAll('.alsel-swipe-banner__slide');
    if (!track || slides.length === 0) return;

    function setActive(i){
      dots.forEach((d, idx) => d.setAttribute('aria-current', idx === i ? 'true' : 'false'));
    }
    setActive(0);

    dots.forEach((dot, i) => {
      dot.addEventListener('click', () => {
        slides[i].scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' });
      });
    });

    let timer = null;
    const io = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          const idx = Array.from(slides).indexOf(e.target);
          if (idx >= 0) setActive(idx);
        }
      });
    }, { root: track, threshold: 0.6 });
    slides.forEach(s => io.observe(s));

    if (root.dataset.autoplay === 'true' && slides.length > 1) {
      const interval = parseInt(root.dataset.interval, 10) || 5000;
      let current = 0;
      timer = setInterval(() => {
        current = (current + 1) % slides.length;
        slides[current].scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' });
      }, interval);
      root.addEventListener('mouseenter', () => clearInterval(timer));
      root.addEventListener('touchstart', () => clearInterval(timer), { passive: true });
    }
  })();
</script>

