{%- assign uid = section.id | replace: '_', '-' -%}

<section class="alsel-tab-product-list" aria-label="{{ section.settings.heading | escape }}">
  <div class="alsel-tab-product-list__inner">
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-tab-product-list__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="alsel-tab-product-list__sub">{{ section.settings.subheading }}</p>
    {%- endif -%}

    {%- if section.blocks.size == 0 -%}
      <p class="alsel-tab-product-list__empty" style="text-align:center;color:#888;padding:2rem 0;">
        現在表示できるタブはありません。テーマエディタからタブブロックを追加してください。
      </p>
    {%- else -%}
      <div class="alsel-tab-product-list__tabs" role="tablist">
        {%- for block in section.blocks -%}
          <input
            type="radio"
            class="alsel-tab-product-list__radio"
            name="alsel-tab-{{ uid }}"
            id="alsel-tab-{{ uid }}-{{ forloop.index }}"
            {% if forloop.first %}checked{% endif %}
          >
          <label
            class="alsel-tab-product-list__label"
            for="alsel-tab-{{ uid }}-{{ forloop.index }}"
            role="tab"
          >{{ block.settings.tab_label | escape }}</label>
        {%- endfor -%}

        {%- for block in section.blocks -%}
          {%- assign tab_collection = collections[block.settings.collection] -%}
          <div class="alsel-tab-product-list__panel" role="tabpanel" {{ block.shopify_attributes }}>
            {%- if tab_collection != blank and tab_collection.products.size > 0 -%}
              <div class="alsel-tab-product-list__grid">
                {%- assign limit = section.settings.product_count -%}
                {%- for product in tab_collection.products limit: limit -%}
                  {%- assign p_alt = product.featured_image.alt | default: product.title | escape -%}
                  <a class="alsel-tab-product-list__card" href="{{ product.url }}" aria-label="{{ product.title | escape }}">
                    <div class="alsel-tab-product-list__media">
                      {%- if product.featured_image != blank -%}
                        {{ product.featured_image | image_url: width: 600 | image_tag: loading: 'lazy', alt: p_alt, class: 'alsel-tab-product-list__img', widths: '200, 300, 400, 600', sizes: '(min-width: 750px) 25vw, 50vw' }}
                      {%- else -%}
                        <div class="alsel-tab-product-list__noimg" aria-hidden="true">No Image</div>
                      {%- endif -%}
                      {%- if product.compare_at_price > product.price -%}
                        <span class="alsel-tab-product-list__badge">SALE</span>
                      {%- endif -%}
                    </div>
                    <h3 class="alsel-tab-product-list__name">{{ product.title | escape }}</h3>
                    <div class="alsel-tab-product-list__price">
                      {%- if product.compare_at_price > product.price -%}
                        <span class="alsel-tab-product-list__price-now">{{ product.price | money }}</span>
                        <span class="alsel-tab-product-list__price-was">{{ product.compare_at_price | money }}</span>
                      {%- else -%}
                        <span class="alsel-tab-product-list__price-now">{{ product.price | money }}</span>
                      {%- endif -%}
                    </div>
                  </a>
                {%- endfor -%}
              </div>
              {%- if block.settings.view_all_url != blank -%}
                <div class="alsel-tab-product-list__more">
                  <a class="alsel-tab-product-list__more-link" href="{{ block.settings.view_all_url }}">
                    {{ block.settings.view_all_text | default: 'すべて見る' }}
                  </a>
                </div>
              {%- endif -%}
            {%- else -%}
              <p class="alsel-tab-product-list__no-products">
                このタブに表示できる商品はありません。テーマエディタからコレクションを紐づけてください。
              </p>
            {%- endif -%}
          </div>
        {%- endfor -%}
      </div>
    {%- endif -%}
  </div>
</section>

