{%- assign heading_safe = section.settings.heading | escape -%}

<section class="alsel-ugc-gallery" aria-label="{{ heading_safe }}" style="--alsel-ugc-gallery-bg: {{ section.settings.bg_color }}; --alsel-ugc-gallery-text: {{ section.settings.text_color }}; --alsel-ugc-gallery-card-bg: {{ section.settings.card_bg }}; --alsel-ugc-gallery-cols: {{ section.settings.columns }};">
