      </p>
    {%- else -%}
      <div class="alsel-ugc-gallery__grid">
        {%- for block in section.blocks -%}
          {%- assign alt_text = block.settings.user_name | default: heading_safe | escape -%}
          <article class="alsel-ugc-gallery__card" {{ block.shopify_attributes }}>
            <div class="alsel-ugc-gallery__media">
              {%- if block.settings.photo != blank -%}
                {{ block.settings.photo | image_url: width: 800 | image_tag: loading: 'lazy', class: 'alsel-ugc-gallery__photo', alt: alt_text, widths: '300, 500, 800' }}
              {%- else -%}
                <div class="alsel-ugc-gallery__placeholder" aria-hidden="true">📷</div>
              {%- endif -%}
