{%- assign sec_heading = section.settings.heading | escape -%}

<section class="alsel-use-case-recommendations" aria-label="{{ sec_heading }}">
  <div class="alsel-use-case-recommendations__inner">
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-use-case-recommendations__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.subheading != blank -%}
      <p class="alsel-use-case-recommendations__sub">{{ section.settings.subheading }}</p>
    {%- endif -%}

    {%- if section.blocks.size == 0 -%}
      <p class="alsel-use-case-recommendations__empty">
        現在表示できる用途はありません。テーマエディタからブロックを追加してください。
      </p>
    {%- else -%}
      <div class="alsel-use-case-recommendations__tabs" role="tablist">
        {%- for block in section.blocks -%}
          <button
            type="button"
            role="tab"
            class="alsel-use-case-recommendations__tab{%- if forloop.first %} is-active{%- endif -%}"
            data-target="alsel-uc-panel-{{ block.id }}"
            aria-selected="{%- if forloop.first %}true{%- else %}false{%- endif -%}"
            {{ block.shopify_attributes }}
          >
            {%- if block.settings.icon != blank -%}
              {%- assign icon_alt = block.settings.tab_label | escape -%}
              {{ block.settings.icon | image_url: width: 80 | image_tag: loading: 'lazy', class: 'alsel-use-case-recommendations__tab-icon', alt: icon_alt }}
            {%- endif -%}
            <span class="alsel-use-case-recommendations__tab-label">{{ block.settings.tab_label }}</span>
          </button>
        {%- endfor -%}
      </div>

      <div class="alsel-use-case-recommendations__panels">
        {%- for block in section.blocks -%}
          <div
            id="alsel-uc-panel-{{ block.id }}"
            class="alsel-use-case-recommendations__panel{%- if forloop.first %} is-active{%- endif -%}"
            role="tabpanel"
          >
            <div class="alsel-use-case-recommendations__panel-head">
              <h3 class="alsel-use-case-recommendations__panel-title">{{ block.settings.title }}</h3>
              {%- if block.settings.description != blank -%}
                <p class="alsel-use-case-recommendations__panel-desc">{{ block.settings.description }}</p>
              {%- endif -%}
            </div>

            <div class="alsel-use-case-recommendations__products">
              {%- assign has_product = false -%}
              {%- if block.settings.product_1 != blank or block.settings.product_2 != blank or block.settings.product_3 != blank or block.settings.product_4 != blank -%}
                {%- assign has_product = true -%}
              {%- endif -%}

              {%- if has_product == false -%}
                <p class="alsel-use-case-recommendations__no-product">
                  このタブに表示する商品をテーマエディタから追加してください。
                </p>
              {%- else -%}
                {%- for i in (1..4) -%}
                  {%- assign key = 'product_' | append: i -%}
                  {%- assign p = block.settings[key] -%}
                  {%- if p != blank -%}
                  {%- assign p_alt = p.title | escape -%}
                  <a class="alsel-use-case-recommendations__card" href="{{ p.url }}" aria-label="{{ p_alt }}の詳細を見る">
                    <div class="alsel-use-case-recommendations__card-media">
                      {%- if p.featured_image != blank -%}
                        {{ p.featured_image | image_url: width: 600 | image_tag: loading: 'lazy', class: 'alsel-use-case-recommendations__card-img', alt: p_alt, widths: '300, 600, 900' }}
                      {%- else -%}
                        <div class="alsel-use-case-recommendations__card-placeholder" aria-hidden="true"></div>
                      {%- endif -%}
                    </div>
                    <div class="alsel-use-case-recommendations__card-body">
                      <p class="alsel-use-case-recommendations__card-title">{{ p.title }}</p>
                      <p class="alsel-use-case-recommendations__card-price">{{ p.price | money }}</p>
                    </div>
                  </a>{%- endif -%}
                {%- endfor -%}
              {%- endif -%}
            </div>

            {%- if block.settings.cta_text != blank and block.settings.cta_link != blank -%}
              <div class="alsel-use-case-recommendations__cta-wrap">
                <a class="alsel-use-case-recommendations__cta" href="{{ block.settings.cta_link }}">
                  {{ block.settings.cta_text }}
                </a>
              </div>
            {%- endif -%}
          </div>
        {%- endfor -%}
      </div>
    {%- endif -%}
  </div>
</section>

