  .alsel-use-case-recommendations__panel-desc { font-size: 0.95rem; line-height: 1.7; color: #475569; margin: 0; max-width: 720px; margin-left: auto; margin-right: auto; }
  .alsel-use-case-recommendations__products { display: grid; grid-template-columns: repeat(2, 1fr); gap: 1rem; }
  .alsel-use-case-recommendations__card { display: block; background: #fff; border-radius: 12px; overflow: hidden; text-decoration: none; color: inherit; box-shadow: 0 2px 8px rgba(0,0,0,0.05); transition: transform 0.2s ease, box-shadow 0.2s ease; }
  .alsel-use-case-recommendations__card:hover { transform: translateY(-3px); box-shadow: 0 6px 16px rgba(0,0,0,0.1); }
  .alsel-use-case-recommendations__card-media { aspect-ratio: 1 / 1; overflow: hidden; background: #f1f5f9; }
  .alsel-use-case-recommendations__card-img { width: 100%; height: 100%; object-fit: cover; display: block; }
  .alsel-use-case-recommendations__card-placeholder { width: 100%; height: 100%; background: linear-gradient(135deg, #f1f5f9, #e2e8f0); }
  .alsel-use-case-recommendations__card-body { padding: 0.9rem; }
  .alsel-use-case-recommendations__card-title { font-size: 0.9rem; font-weight: 600; line-height: 1.5; margin: 0 0 0.4rem; color: #1f2937; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
  .alsel-use-case-recommendations__card-price { font-size: 0.95rem; font-weight: 700; color: var(--accent); margin: 0; }
  .alsel-use-case-recommendations__cta-wrap { text-align: center; margin: 2rem 0 0; }
  .alsel-use-case-recommendations__cta { display: inline-block; padding: 0.85rem 2.2rem; background: var(--accent); color: #fff; text-decoration: none; border-radius: 9999px; font-weight: 700; font-size: 0.95rem; transition: opacity 0.2s ease; }
  .alsel-use-case-recommendations__cta:hover { opacity: 0.85; }
  @media (min-width: 750px) {
    .alsel-use-case-recommendations { padding: 5rem 2rem; }
    .alsel-use-case-recommendations__tab { padding: 0.85rem 1.6rem; font-size: 0.95rem; }
    .alsel-use-case-recommendations__products { grid-template-columns: repeat(4, 1fr); gap: 1.5rem; }
    .alsel-use-case-recommendations__card-body { padding: 1.1rem; }
    .alsel-use-case-recommendations__card-title { font-size: 0.95rem; }
  }
</style>

<script>
  (function() {
    var root = document.currentScript.closest('.alsel-use-case-recommendations');
    if (!root) return;
    var tabs = root.querySelectorAll('.alsel-use-case-recommendations__tab');
    var panels = root.querySelectorAll('.alsel-use-case-recommendations__panel');
    tabs.forEach(function(tab) {
      tab.addEventListener('click', function() {
        var target = tab.getAttribute('data-target');
        tabs.forEach(function(t) { t.classList.remove('is-active'); t.setAttribute('aria-selected', 'false'); });
        panels.forEach(function(p) { p.classList.remove('is-active'); });
        tab.classList.add('is-active');
        tab.setAttribute('aria-selected', 'true');
        var panel = root.querySelector('#' + target);
        if (panel) panel.classList.add('is-active');
      });
    });
  })();
</script>

